import os, re, json

def parse_frontmatter(filepath):
    with open(filepath, 'r') as f:
        content = f.read()
    match = re.match(r'^---\s*\n(.*?)\n---', content, re.DOTALL)
    if not match:
        return None
    # Simple YAML parsing without pyyaml
    fm = {}
    raw = match.group(1)
    for line in raw.split('\n'):
        line = line.strip()
        if not line or line.startswith('#'):
            continue
        if ':' in line:
            key, val = line.split(':', 1)
            key = key.strip()
            val = val.strip()
            # Handle list values on same line [a, b, c]
            if val.startswith('[') and val.endswith(']'):
                items = [x.strip().strip('"').strip("'") for x in val[1:-1].split(',') if x.strip()]
                fm[key] = items
            elif val == '':
                # Possibly a multi-line list follows
                fm[key] = []
            elif val.startswith('"') and val.endswith('"'):
                fm[key] = val.strip('"')
            elif val.startswith("'") and val.endswith("'"):
                fm[key] = val.strip("'")
            else:
                # Try int
                try:
                    fm[key] = int(val)
                except ValueError:
                    fm[key] = val
        elif line.startswith('- ') and fm:
            # Append to last list key
            last_key = list(fm.keys())[-1]
            if isinstance(fm[last_key], list):
                fm[last_key].append(line[2:].strip().strip('"').strip("'"))
    return fm

results = {'concepts': [], 'connections': []}

for folder in ['concepts', 'connections']:
    dirpath = os.path.join('.', folder)
    if not os.path.isdir(dirpath):
        continue
    for fname in sorted(os.listdir(dirpath)):
        if not fname.endswith('.md'):
            continue
        fpath = os.path.join(dirpath, fname)
        fm = parse_frontmatter(fpath)
        if fm:
            fm['_file'] = fname
            fm['_folder'] = folder
            results[folder].append(fm)
        else:
            print(f"WARNING: No frontmatter in {fpath}")

print(json.dumps(results, indent=2, default=str))
